PRAGMA foreign_keys = ON;

CREATE TABLE Airports (Id INTEGER PRIMARY KEY AUTOINCREMENT, Code TEXT NOT NULL UNIQUE, Name TEXT NOT NULL, City TEXT NOT NULL, Country TEXT NOT NULL, Terminal TEXT NOT NULL, IsActive INTEGER NOT NULL);
CREATE TABLE Airlines (Id INTEGER PRIMARY KEY AUTOINCREMENT, Name TEXT NOT NULL, IataCode TEXT NOT NULL UNIQUE, Country TEXT NOT NULL, Phone TEXT NOT NULL, Website TEXT NOT NULL, IsActive INTEGER NOT NULL);
CREATE TABLE Flights (Id INTEGER PRIMARY KEY AUTOINCREMENT, FlightNumber TEXT NOT NULL, AirlineId INTEGER NOT NULL, DepartureAirportId INTEGER NOT NULL, ArrivalAirportId INTEGER NOT NULL, DepartureTime TEXT NOT NULL, ArrivalTime TEXT NOT NULL, Price NUMERIC NOT NULL, AvailableSeats INTEGER NOT NULL, HasStopover INTEGER NOT NULL, Status TEXT NOT NULL, Gate TEXT NOT NULL, FOREIGN KEY(AirlineId) REFERENCES Airlines(Id), FOREIGN KEY(DepartureAirportId) REFERENCES Airports(Id), FOREIGN KEY(ArrivalAirportId) REFERENCES Airports(Id));
CREATE TABLE Passengers (Id INTEGER PRIMARY KEY AUTOINCREMENT, FullName TEXT NOT NULL, Email TEXT NOT NULL UNIQUE, Phone TEXT NOT NULL, PassportNumber TEXT NOT NULL, Nationality TEXT NOT NULL, BirthDate TEXT NOT NULL, CreatedAt TEXT NOT NULL);
CREATE TABLE Bookings (Id INTEGER PRIMARY KEY AUTOINCREMENT, BookingCode TEXT NOT NULL UNIQUE, PassengerId INTEGER NOT NULL, FlightId INTEGER NOT NULL, PassengerCount INTEGER NOT NULL, TripType TEXT NOT NULL, BookingDate TEXT NOT NULL, TotalPrice NUMERIC NOT NULL, Status TEXT NOT NULL, Notes TEXT NOT NULL, FOREIGN KEY(PassengerId) REFERENCES Passengers(Id), FOREIGN KEY(FlightId) REFERENCES Flights(Id));
